// Entrada esperada (Chat Trigger):
// { sessionId, action, chatInput: "https://fonestar.com max=200" }

const raw = String($json.chatInput ?? '').trim();
if (!raw) throw new Error('Falta chatInput. Ej: https://fonestar.com max=20');

// Normalizar texto
const text = raw
  .replace(/[\u200B-\u200D\uFEFF]/g, '')   // invisibles
  .replace(/\r\n|\r|\n/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// max=NN (opcional)
let maxProducts = 20;
const mm = text.match(/(?:^|\s)max\s*=\s*(\d+)/i);
if (mm?.[1]) {
  const n = parseInt(mm[1], 10);
  if (Number.isFinite(n)) maxProducts = Math.min(Math.max(n, 1), 2000);
}

// Sacar URL/dominio (primer token razonable)
const tokens = text.split(' ');
let candidate = '';

for (let t of tokens) {
  t = t.trim()
    .replace(/^[<("'[{]+/g, '')
    .replace(/[>\)"'\]}.,;:!?]+$/g, '');
  if (!t) continue;

  if (
    t.startsWith('http://') ||
    t.startsWith('https://') ||
    t.startsWith('//') ||
    t.startsWith('www.') ||
    t.includes('.')
  ) {
    candidate = t;
    break;
  }
}

if (!candidate) {
  throw new Error('No encontré URL/dominio en el mensaje. Ej: https://fonestar.com max=200');
}

// Normalizar URL (sin usar new URL)
candidate = candidate
  .replace(/(https?)\s*:\s*\/\//i, '$1://') // "https : //"
  .replace(/(https?)\s+\/\//i, '$1://');    // "https //"

if (candidate.startsWith('//')) candidate = 'https:' + candidate;
if (candidate.startsWith('www.')) candidate = 'https://' + candidate;
if (!/^https?:\/\//i.test(candidate)) candidate = 'https://' + candidate;

// origin
const mOrigin = candidate.match(/^(https?:\/\/[^\/?#]+)/i);
if (!mOrigin) throw new Error(`URL inválida: "${candidate}"`);

const origin = mOrigin[1];

return [{
  json: {
    inputText: text,
    targetUrl: candidate,
    origin,
    maxProducts,
    userAgent: 'Mozilla/5.0 (n8n-scraper)'
  }
}];

/**
 * Build Candidates (simple y robusto)
 * Entrada:
 *  - origin (desde Parse Chat Command, vía Include Input Data o Merge)
 *  - robots.txt en data/body/text
 * Salida:
 *  - items { candidateUrl }
 */

// --- Obtener origin de forma robusta ---
let origin = $json.origin;

if (!origin) {
  try {
    origin = $items('Parse Chat Command')[0].json.origin;
  } catch (e) {}
}

origin = String(origin || '').replace(/\/+$/,'').trim();

if (!origin) {
  throw new Error('Falta origin. Asegura Include Input Data o usa Merge.');
}

// --- Obtener contenido robots.txt ---
function getRobots(obj) {
  for (const k of ['body','data','text','response']) {
    if (typeof obj?.[k] === 'string' && obj[k].trim()) return obj[k];
  }
  for (const v of Object.values(obj || {})) {
    if (typeof v === 'string' && v.trim()) return v;
  }
  return '';
}

const robotsStr = getRobots($json);

if (!robotsStr) {
  // Si no hay robots, seguimos con defaults
  console.log('robots.txt vacío, usando fallbacks.');
}

// --- Extraer Sitemap: del robots ---
const found = [];
const lines = String(robotsStr || '').split(/\r?\n/);

for (const line of lines) {
  const match = line.match(/^\s*sitemap:\s*(\S+)/i);
  if (match && match[1]) {
    found.push(match[1].trim());
  }
}

// --- Fallbacks típicos ---
const defaults = [
  origin + '/sitemap.xml',
  origin + '/sitemap_index.xml',
  origin + '/sitemap-index.xml',
  origin + '/sitemapindex.xml',
  origin + '/wp-sitemap.xml'
];

// Opcionales HTML (por si no hay XML)
const html = [
  origin + '/sitemap',
  origin + '/en/sitemap',
  origin + '/es/sitemap',
  origin + '/de/sitemap'
];

// --- Combinar y deduplicar ---
const candidates = [...found, ...defaults, ...html]
  .filter(Boolean);

const uniq = [...new Set(candidates)];

// --- Output ---
return uniq.map(u => ({
  json: {
    candidateUrl: u
  }
}));

/**
 * Pick + Parse Candidate (robusto y sencillo)
 * Limitado a maxProducts (200 por defecto)
 */

// 1) Obtener origin y meta
const firstIn = $input.first()?.json ?? {};
const meta = (() => {
  try { return $items('Parse Chat Command')[0].json; } catch (e) { return {}; }
})();

const origin = firstIn.origin || meta.origin || '';
const MAX_ITEMS = meta.maxProducts || 200;

// limpiar invisibles
const clean = (s) => String(s || '').replace(/[\u200B-\u200D\uFEFF]/g, '').trim();

// host sin new URL
const originHost = (() => {
  const m = clean(origin).match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() : '';
})();

// 2) Obtener bodies
const all = $input.all().map(x => x.json);

function getBody(o) {
  for (const k of ['body', 'data', 'response', 'text']) {
    if (typeof o?.[k] === 'string' && o[k].trim()) return o[k];
  }
  for (const v of Object.values(o || {})) {
    if (typeof v === 'string' && v.length > 50) return v;
  }
  return '';
}

function decodeEntities(s) {
  return String(s || '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

function toAbsoluteUrl(href) {
  const h = clean(decodeEntities(href));
  if (!h) return '';

  if (
    h.startsWith('#') ||
    h.startsWith('mailto:') ||
    h.startsWith('tel:') ||
    h.startsWith('javascript:')
  ) return '';

  if (/^https?:\/\//i.test(h)) return h;

  if (h.startsWith('//')) {
    const scheme = clean(origin).startsWith('http://') ? 'http:' : 'https:';
    return scheme + h;
  }

  if (origin) {
    if (h.startsWith('/')) return clean(origin).replace(/\/+$/,'') + h;
    return clean(origin).replace(/\/+$/,'') + '/' + h;
  }

  return '';
}

function sameHost(url) {
  if (!originHost) return true;
  const m = clean(url).match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() === originHost : false;
}

// 3) Elegir mejor body
let bestScore = 0;
let bestBody = '';

for (const o of all) {
  const body = clean(getBody(o));
  if (!body) continue;

  const b = body.toLowerCase();
  let score = 0;
  if (b.includes('<urlset')) score = 3;
  else if (b.includes('<sitemapindex')) score = 2;
  else if (b.includes('<html')) score = 1;

  if (score > bestScore) {
    bestScore = score;
    bestBody = body;
  }
}

// 4) Parsear
let pageUrls = [];
let childSitemaps = [];

if (bestScore === 3) {
  const locRe = /<loc>\s*([^<\s]+)\s*<\/loc>/gi;
  for (const m of bestBody.matchAll(locRe)) {
    const u = clean(decodeEntities(m[1]));
    if (!u) continue;
    if (!sameHost(u)) continue;
    pageUrls.push(u);
  }
} else if (bestScore === 2) {
  const locRe = /<loc>\s*([^<\s]+)\s*<\/loc>/gi;
  for (const m of bestBody.matchAll(locRe)) {
    const u = clean(decodeEntities(m[1]));
    if (!u) continue;

    const lu = u.toLowerCase();
    const looksSitemap = lu.includes('sitemap') || lu.endsWith('.xml') || lu.endsWith('.xml.gz');
    if (looksSitemap) childSitemaps.push(u);
  }
} else if (bestScore === 1) {
  const hrefRe = /href=["']([^"']+)["']/gi;
  for (const m of bestBody.matchAll(hrefRe)) {
    const abs = toAbsoluteUrl(m[1]);
    if (!abs) continue;
    if (!sameHost(abs)) continue;

    const lu = abs.toLowerCase();
    const looksSitemap = lu.includes('sitemap') || lu.endsWith('.xml') || lu.endsWith('.xml.gz');
    if (looksSitemap) childSitemaps.push(abs);
    else pageUrls.push(abs);
  }
}

// dedupe
pageUrls = [...new Set(pageUrls)];
childSitemaps = [...new Set(childSitemaps)];

// 🔒 LIMITAR RESULTADOS
pageUrls = pageUrls.slice(0, MAX_ITEMS);

if (pageUrls.length < MAX_ITEMS) {
  childSitemaps = childSitemaps.slice(0, MAX_ITEMS - pageUrls.length);
} else {
  childSitemaps = [];
}

// 5) Output
const out = [];

if (pageUrls.length === 0) {
  out.push({ json: { kind: 'pageUrl', url: '', isDummy: true } });
} else {
  for (const u of pageUrls) {
    out.push({ json: { kind: 'pageUrl', url: u, isDummy: false } });
  }
}

if (childSitemaps.length === 0) {
  out.push({ json: { kind: 'childSitemap', url: '', isDummy: true } });
} else {
  for (const u of childSitemaps) {
    out.push({ json: { kind: 'childSitemap', url: u, isDummy: false } });
  }
}

return out;

/**
 * Parse Child Sitemap (simple y robusto)
 * Entrada: items con el XML del child sitemap en body/data/text/response
 * Output: items { kind:'pageUrl', url, isDummy }
 */

// 1) origin / host (robusto)
const firstIn = $input.first()?.json ?? {};
let origin = firstIn.origin;

if (!origin) {
  // fallback: intentar leer del nodo Parse Chat Command si existe
  try { origin = $items('Parse Chat Command')[0].json.origin; } catch (e) {}
}

origin = String(origin || '').trim();

// host sin new URL()
const originHost = (() => {
  const m = origin.match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() : '';
})();

function getBody(o) {
  for (const k of ['body', 'data', 'response', 'text']) {
    if (typeof o?.[k] === 'string' && o[k].trim()) return o[k];
  }
  for (const v of Object.values(o || {})) {
    if (typeof v === 'string' && v.length > 50) return v;
  }
  return '';
}

function decodeEntities(s) {
  return String(s || '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

function strip(s) {
  return String(s || '')
    .replace(/[\u200B-\u200D\uFEFF]/g, '') // invisibles
    .trim();
}

function sameHost(url) {
  if (!originHost) return true; // si no sabemos host, no filtramos
  const m = strip(url).match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() === originHost : false;
}

function toAbsolute(u) {
  let s = strip(decodeEntities(u));
  if (!s) return '';

  // si ya es absoluta
  if (/^https?:\/\//i.test(s)) return s;

  // protocol-relative
  if (s.startsWith('//')) {
    const scheme = origin.startsWith('http://') ? 'http:' : 'https:';
    return scheme + s;
  }

  // relativa
  if (origin) {
    const base = origin.replace(/\/+$/g, '');
    if (s.startsWith('/')) return base + s;
    return base + '/' + s;
  }

  return '';
}

// 2) parse <loc> en todos los inputs
const all = $input.all().map(i => i.json);
const pageUrls = [];

const locRe = /<loc>\s*([^<\s]+)\s*<\/loc>/gi;

for (const o of all) {
  const body = strip(getBody(o));
  if (!body) continue;

  for (const m of body.matchAll(locRe)) {
    const rawLoc = m[1];
    const abs = toAbsolute(rawLoc);
    if (!abs) continue;

    const lu = abs.toLowerCase();
    // excluir sitemaps
    if (lu.endsWith('.xml') || lu.endsWith('.xml.gz') || lu.includes('sitemap')) continue;

    if (!sameHost(abs)) continue;

    pageUrls.push(abs);
  }
}

// 3) dedupe + output
const uniq = [...new Set(pageUrls)];

if (uniq.length === 0) {
  return [{ json: { kind: 'pageUrl', url: '', isDummy: true } }];
}

return uniq.map(u => ({ json: { kind: 'pageUrl', url: u, isDummy: false } }));

/**
 * Filter + Limit URLs (sin new URL)
 * Entrada: items { kind:'pageUrl', url }
 * Usa meta de Parse Chat Command: origin + maxProducts
 * Salida: items { url } o { noUrls:true }
 */

// --- meta robusto ---
let meta = {};
try { meta = $items('Parse Chat Command')[0].json; } catch (e) { meta = {}; }

const origin = String(meta.origin || '').trim();
const max = Number(meta.maxProducts || 200);

if (!origin) throw new Error('Falta origin (desde Parse Chat Command).');

const originHost = (() => {
  const m = origin.match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() : '';
})();

const originScheme = origin.startsWith('http://') ? 'http:' : 'https:';

const cleanStr = (s) =>
  String(s || '')
    .replace(/[\u200B-\u200D\uFEFF]/g, '') // invisibles
    .replace(/\s+/g, ' ')
    .trim();

const decodeEntities = (s) =>
  String(s || '').replace(/&amp;/g, '&');

function getHost(u) {
  const m = cleanStr(u).match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() : '';
}

function getPath(u) {
  // devuelve pathname sin query/fragment
  const s = cleanStr(u);
  const m = s.match(/^https?:\/\/[^\/?#]+(\/[^?#]*)?/i);
  return (m && m[1]) ? m[1] : '/';
}

function normalizeUrl(u) {
  let s = cleanStr(decodeEntities(u));

  if (!s) return '';

  // arreglos básicos si vienen partidos
  s = s.replace(/(https?)\s*:\s*\/\//i, '$1://');
  s = s.replace(/(https?)\s+\/\//i, '$1://');

  // quitar fragment
  s = s.split('#')[0];

  // protocol-relative
  if (s.startsWith('//')) s = originScheme + s;

  // relativo a origin
  if (s.startsWith('/')) s = origin.replace(/\/+$/,'') + s;

  // relativo sin slash
  if (!/^https?:\/\//i.test(s)) s = origin.replace(/\/+$/,'') + '/' + s;

  return s;
}

// --- recolectar urls pageUrl ---
const urls = [];
for (const it of $input.all()) {
  const j = it.json || {};
  if (j.kind === 'pageUrl' && j.url) urls.push(j.url);
}

// --- dedupe (antes de normalizar) ---
const ded = [...new Set(urls.map(cleanStr).filter(Boolean))];

// --- filtros ---
const badExt = [
  '.jpg','.jpeg','.png','.gif','.webp','.svg',
  '.css','.js','.pdf','.zip','.rar','.7z',
  '.mp4','.mp3','.wav','.ico',
  '.woff','.woff2','.ttf','.eot'
];

const cleaned = [];

for (const raw of ded) {
  const abs = normalizeUrl(raw);
  if (!abs) continue;

  // filtrar host (si lo conocemos)
  if (originHost) {
    const h = getHost(abs);
    if (!h || h !== originHost) continue;
  }

  const p = getPath(abs).toLowerCase();
  if (badExt.some(ext => p.endsWith(ext))) continue;

  cleaned.push(abs);
}

// dedupe final
const cleanedUniq = [...new Set(cleaned)];

// --- priorizar posibles páginas de producto ---
const productHints = [
  '/product/','/products/','/producto/','/productos/',
  '/shop/','/store/','/tienda/',
  '/catalog','/catalogo',
  '/item/','/p/','/prod'
];

const hinted = cleanedUniq.filter(u =>
  productHints.some(h => u.toLowerCase().includes(h))
);

// regla: si hay suficientes “hinted”, usa esas; si no, usa todas
const threshold = Math.min(50, max);
const chosen = (hinted.length >= threshold) ? hinted : cleanedUniq;

const final = chosen.slice(0, max);

if (final.length === 0) {
  return [{ json: { noUrls: true } }];
}

return final.map(u => ({ json: { url: u } }));

/**
 * Build JSON File (robusto y compatible con tu entorno)
 * Genera binario JSON listo para enviar por Telegram
 */

// --- META ---
let meta = {};
try { meta = $items('Parse Chat Command')[0].json; } catch (e) { meta = {}; }

const chatId = meta.chatId || null;
const src = meta.targetUrl || '';
const origin = meta.origin || '';
const now = new Date().toISOString();

// --- INPUT ITEMS ---
const items = $input.all().map(i => i.json || {});

// --- PRODUCTOS VÁLIDOS ---
const validProducts = items.filter(p => p && p.isProduct && p.name);

// --- LISTA PLANA ---
const products = validProducts.map(p => ({
  name: p.name || null,
  price: p.price ?? null,
  currency: p.currency ?? null,
  url: p.url || null,
  sku: p.sku || null
}));

// --- AGRUPAR POR CATEGORÍA ---
const byCat = new Map();

for (const p of validProducts) {
  let c = (p.category || 'Sin categoria');
  c = String(c).trim();
  if (!c) c = 'Sin categoria';

  if (!byCat.has(c)) byCat.set(c, []);

  byCat.get(c).push({
    name: p.name || null,
    price: p.price ?? null,
    currency: p.currency ?? null,
    url: p.url || null,
    sku: p.sku || null
  });
}

// --- ORDENAR CATEGORÍAS ---
const categories = [...byCat.entries()]
  .sort((a, b) => a[0].localeCompare(b[0]))
  .map(([name, prods]) => ({
    name,
    products: prods
  }));

// --- CATALOGO FINAL ---
const catalog = {
  source: src,
  generated_at: now,
  total_products: products.length,
  categories
};

const jsonStr = JSON.stringify(catalog, null, 2);

// --- HOST SEGURO (sin new URL) ---
let host = 'unknown';

const hostMatch = String(origin).match(/^https?:\/\/([^\/?#]+)/i);
if (hostMatch) {
  host = hostMatch[1].replace(/[^a-zA-Z0-9.-]/g, '_');
}

const fileName = `catalog_${host}_${Date.now()}.json`;

// --- OUTPUT BINARIO ---
return [{
  json: {
    chatId,
    fileName,
    total_products: products.length
  },
  binary: {
    data: {
      data: Buffer.from(jsonStr, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName
    }
  }
}];
